Let's start by creating the basic structure of the scientific calculator in `index.html`.

```html
<!doctype html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Scientific Calculator</title>
    <link rel="stylesheet" href="style.css">
</head>
<body>
    <div id="app">
        <input type="text" id="display" disabled>
        <button onclick="clearDisplay()">C</button>
        <button onclick="memoryStore()">M+</button>
        <button onclick="memoryRecall()">MR</button>
        <button onclick="deleteLast()">DEL</button>
        <button onclick="append('7')">7</button>
        <button onclick="append('8')">8</button>
        <button onclick="append('9')">9</button>
        <button onclick="append('/')">/</button>
        <button onclick="append('4')">4</button>
        <button onclick="append('5')">5</button>
        <button onclick="append('6')">6</button>
        <button onclick="append('*')">*</button>
        <button onclick="append('1')">1</button>
        <button onclick="append('2')">2</button>
        <button onclick="append('3')">3</button>
        <button onclick="append('-')">-</button>
        <button onclick="append('0')">0</button>
        <button onclick="append('.')">.</button>
        <button onclick="append('+')">+</button>
        <button onclick="calculate()">=</button>
    </div>
    <script src="script.js"></script>
</body>
</html>
```

Now, let's add some basic styling in `style.css`.

```css
#app {
    display: flex;
    flex-direction: column;
    align-items: center;
}

#display {
    width: 200px;
    height: 50px;
    margin-bottom: 10px;
    text-align: right;
    padding: 10px;
    font-size: 24px;
}

button {
    width: 50px;
    height: 50px;
    margin: 5px;
    font-size: 20px;
}
```

Finally, let's add the JavaScript logic in `script.js`.

```javascript
let display = document.getElementById('display');
let memory = null;

function clearDisplay() {
    display.value = '';
}

function memoryStore() {
    if (display.value) {
        memory = parseFloat(display.value);
    }
}

function memoryRecall() {
    if (memory !== null) {
        display.value = memory;
    }
}

function deleteLast() {
    display.value = display.value.slice(0, -1);
}

function append(value) {
    display.value += value;
}

function calculate() {
    try {
        display.value = eval(display.value);
    } catch (e) {
        display.value = 'Error';
    }
}
```

